CREATE EXTENSION IF NOT EXISTS pgcrypto;CREATE TYPE user_role AS ENUM('super_admin','admin_staff','teacher','accountant');CREATE TYPE attendance_status AS ENUM('Present','Absent');CREATE TYPE complaint_status AS ENUM('Pending','Processing','Solved');CREATE SEQUENCE IF NOT EXISTS payments_receipt_seq START 1001;
CREATE TABLE users(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),username VARCHAR(60) UNIQUE NOT NULL,name VARCHAR(120) NOT NULL,email VARCHAR(160) UNIQUE NOT NULL,password_hash TEXT NOT NULL,role user_role NOT NULL,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE academic_years(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(30) UNIQUE NOT NULL,start_date DATE,end_date DATE,is_active BOOLEAN DEFAULT FALSE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE classes(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(80) NOT NULL,academic_year_id UUID REFERENCES academic_years(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE sections(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(30) NOT NULL,class_id UUID REFERENCES classes(id) ON DELETE CASCADE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(name,class_id));
CREATE TABLE courses(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(80) UNIQUE NOT NULL,code VARCHAR(20) UNIQUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE subjects(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(100) NOT NULL,code VARCHAR(20) UNIQUE,course_id UUID REFERENCES courses(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE students(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),student_code VARCHAR(40) UNIQUE DEFAULT('VJC-'||TO_CHAR(NOW(),'YYYY')||'-'||UPPER(SUBSTR(REPLACE(gen_random_uuid()::text,'-',''),1,6))),admission_number VARCHAR(50) UNIQUE NOT NULL,roll_number VARCHAR(30),name VARCHAR(140) NOT NULL,photo_url TEXT,date_of_birth DATE,gender VARCHAR(20),mobile VARCHAR(20),email VARCHAR(160),class_id UUID REFERENCES classes(id),section_id UUID REFERENCES sections(id),course_id UUID REFERENCES courses(id),academic_year_id UUID REFERENCES academic_years(id),father_name VARCHAR(120),mother_name VARCHAR(120),parent_mobile VARCHAR(20),address TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE staff(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),staff_code VARCHAR(30) UNIQUE NOT NULL,name VARCHAR(140) NOT NULL,photo_url TEXT,qualification VARCHAR(120),department VARCHAR(100),subject VARCHAR(100),mobile VARCHAR(20),email VARCHAR(160) UNIQUE,address TEXT,joining_date DATE,user_id UUID UNIQUE REFERENCES users(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE fees(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),class_id UUID REFERENCES classes(id),fee_type VARCHAR(100) NOT NULL,amount NUMERIC(12,2) CHECK(amount>=0),academic_year_id UUID REFERENCES academic_years(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE student_fee_allocations(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),student_id UUID REFERENCES students(id) ON DELETE CASCADE,fee_id UUID REFERENCES fees(id),total_amount NUMERIC(12,2) NOT NULL,paid_amount NUMERIC(12,2) DEFAULT 0,balance_amount NUMERIC(12,2) GENERATED ALWAYS AS(total_amount-paid_amount) STORED,due_date DATE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE payments(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),student_id UUID REFERENCES students(id),allocation_id UUID REFERENCES student_fee_allocations(id),receipt_number VARCHAR(50) UNIQUE DEFAULT('VJC-R-'||TO_CHAR(NOW(),'YYYYMMDD')||'-'||NEXTVAL('payments_receipt_seq')),payment_date DATE DEFAULT CURRENT_DATE,amount_paid NUMERIC(12,2) CHECK(amount_paid>0),payment_mode VARCHAR(30) CHECK(payment_mode IN('Cash','UPI','Card','Bank Transfer')),recorded_by UUID REFERENCES users(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE attendance(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),student_id UUID REFERENCES students(id) ON DELETE CASCADE,date DATE NOT NULL,status attendance_status NOT NULL,marked_by UUID REFERENCES users(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(student_id,date));
CREATE TABLE exams(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(120) NOT NULL,class_id UUID REFERENCES classes(id),subject_id UUID REFERENCES subjects(id),maximum_marks NUMERIC(6,2) NOT NULL,exam_date DATE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE marks(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),exam_id UUID REFERENCES exams(id) ON DELETE CASCADE,student_id UUID REFERENCES students(id) ON DELETE CASCADE,marks_obtained NUMERIC(6,2) NOT NULL,entered_by UUID REFERENCES users(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(exam_id,student_id));
CREATE TABLE transport(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),bus_number VARCHAR(40) UNIQUE NOT NULL,driver_name VARCHAR(120),driver_mobile VARCHAR(20),route_name VARCHAR(120),stops TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());CREATE TABLE student_transport(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),student_id UUID REFERENCES students(id),transport_id UUID REFERENCES transport(id),transport_fee_id UUID REFERENCES fees(id),created_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(student_id));
CREATE TABLE messages(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),subject VARCHAR(200) NOT NULL,body TEXT NOT NULL,audience_type VARCHAR(30),audience_id UUID,sender_id UUID REFERENCES users(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE complaints(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),complaint_code VARCHAR(40) UNIQUE NOT NULL,raised_by_type VARCHAR(20),raised_by_id UUID,subject VARCHAR(200) NOT NULL,description TEXT,status complaint_status DEFAULT'Pending',created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE college_settings(id SMALLINT PRIMARY KEY DEFAULT 1 CHECK(id=1),college_name VARCHAR(160) NOT NULL DEFAULT'Values Junior College',address TEXT,phone VARCHAR(20),email VARCHAR(160),logo_url TEXT,updated_at TIMESTAMPTZ DEFAULT NOW());CREATE INDEX idx_students_class_section ON students(class_id,section_id);CREATE INDEX idx_attendance_date_student ON attendance(date,student_id);CREATE INDEX idx_payments_date_student ON payments(payment_date,student_id);CREATE INDEX idx_marks_exam_student ON marks(exam_id,student_id);
